noncompliant:
// Using macros for type definitions
#define INT_PTR int*
#define STRING_ARRAY char**
#define CALLBACK_FUNC void(*)(int)

INT_PTR ptr;
STRING_ARRAY args;
CALLBACK_FUNC handler;

compliant:
// Using typedef for type definitions
typedef int* IntPtr;
typedef char** StringArray;
typedef void (*CallbackFunc)(int);

IntPtr ptr;
StringArray args;
CallbackFunc handler;

// In C++, using declarations are preferred
using IntPtr = int*;
using StringArray = char**;
using CallbackFunc = void(*)(int);
